import { Vex } from '@vex_dev/sdk';
import { ChatFlow } from 'flowise';

const vex = new Vex({
  projectId: 'your-project-id',
  apiKey: process.env.VEX_API_KEY
});

const chatflow = new ChatFlow();
chatflow.setCallbackHandler({
  onChatflowStart: async (metadata) => {
    await vex.span('flowise.chatflow.start', {
      metadata: { tenantId: metadata.tenantId },
      input: metadata.input
    });
  },
  onNodeExecute: async (nodeData) => {
    const validation = await vex.validate({
      guardrail: 'enterprise-accuracy',
      input: nodeData.input,
      output: nodeData.output,
      context: { tenantId: nodeData.tenantId }
    });
    if (!validation.pass) {
      throw new Error(`Guardrail failed: ${validation.reason}`);
    }
  }
});

// Deploy chatflow
await chatflow.deploy();

import { VexGuardrail } from '@vex_dev/sdk';

const vectorGuardrail = new VexGuardrail({
  name: 'flowise-vector-retrieval',
  type: 'retrieval_relevance',
  config: {
    threshold: 0.85,
    maxHallucination: 0.1,
    tenantIsolation: true
  }
});

// In Flowise vector store node callback
const validateRetrieval = async (query: string, docs: Document[]) => {
  const result = await vectorGuardrail.evaluate({
    input: query,
    retrieved: docs.map(d => d.pageContent),
    metadata: { tenantId: getCurrentTenant() }
  });

  if (!result.pass) {
    console.warn('Low-relevance docs filtered:', result.reason);
    return [];
  }
  return docs;
};

import { Vex } from '@vex_dev/sdk';

const vex = new Vex({ projectId: 'saas-enterprise' });

// Global tenant context middleware
const tenantMiddleware = async (req: Request, next: () => Promise<any>) => {
  const tenantId = req.headers.get('x-tenant-id');
  const span = await vex.span('flowise.tenant-context', {
    traceId: req.headers.get('x-trace-id'),
    attributes: { tenantId },
    kind: 'INTERNAL'
  });

  // Propagate to all Flowise nodes
  process.env.CURRENT_TENANT = tenantId;
  span.setAttribute('tenant.isolation', true);

  const result = await next();

  // Validate no cross-tenant data
  await span.validate({
    guardrail: 'tenant-isolation',
    output: result
  });

  return result;
};
